// File: ds_demo.dart
// Run: dart ds_demo.dart
import 'dart:math';

void main() {
  final rand = Random(42);
  final nums = List.generate(10000, (_) => rand.nextInt(9000));

  // Approach 1: LIST (linear search) — O(n²) — slow
  var t0 = DateTime.now();
  var dups1 = 0; final seen1 = <int>[];
  for (final n in nums) {
    if (seen1.contains(n)) dups1++;   // O(n) each time
    else seen1.add(n);
  }
  final ms1 = DateTime.now().difference(t0).inMilliseconds;

  // Approach 2: HASH SET — O(n) — fast
  t0 = DateTime.now();
  var dups2 = 0; final seen2 = <int>{};
  for (final n in nums) {
    if (!seen2.add(n)) dups2++;       // O(1) each time
  }
  final ms2 = DateTime.now().difference(t0).inMilliseconds;

  // Approach 3: HASH MAP with counts — O(n), also gives frequencies
  t0 = DateTime.now();
  final counts = <int, int>{};
  for (final n in nums) counts[n] = (counts[n] ?? 0) + 1;
  var dups3 = counts.values.where((c) => c > 1).length;
  final ms3 = DateTime.now().difference(t0).inMilliseconds;

  print('List / linear search : $dups1 dups in $ms1 ms');
  print('Hash set             : $dups2 dups in $ms2 ms');
  print('Hash map w/ counts   : $dups3 unique nums seen 2+ times in $ms3 ms');
  print('Same answer, but different speeds by orders of magnitude.');
}

// Typical output on a laptop:
// List / linear search : 1015 dups in 1420 ms
// Hash set             : 1015 dups in 3 ms
// Hash map w/ counts   : 8985 unique nums seen 2+ times in 3 ms
// Same answer, but different speeds by orders of magnitude.
//
// The list approach: 400+ TIMES slower than the hash set.
// That's the impact of picking the right data structure.
